CREATE DATABASE IF NOT EXISTS tarimba3
  CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE tarimba3;

SET FOREIGN_KEY_CHECKS = 0;

-- ── professores ────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS professores (
  id            INT          NOT NULL AUTO_INCREMENT,
  nome_completo VARCHAR(120) NOT NULL,
  email         VARCHAR(120) NOT NULL,
  telefone      VARCHAR(30)  NOT NULL DEFAULT '',
  ativo         TINYINT(1)   NOT NULL DEFAULT 1,
  criado_em     DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uq_email (email)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── turmas ─────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS turmas (
  id                VARCHAR(6)  NOT NULL,
  sala              TINYINT     NOT NULL,
  turno             VARCHAR(5)  NOT NULL COMMENT 'Manha|Tarde',
  classe            TINYINT     NOT NULL,
  curso             VARCHAR(3)  NULL     COMMENT 'CG|IG|CEJ|CFB',
  director_turma_id INT         NULL,
  PRIMARY KEY (id),
  FOREIGN KEY (director_turma_id) REFERENCES professores(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── disciplinas ────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS disciplinas (
  id            INT          NOT NULL AUTO_INCREMENT,
  nome          VARCHAR(100) NOT NULL,
  classe_minima TINYINT      NOT NULL DEFAULT 1,
  classe_maxima TINYINT      NOT NULL DEFAULT 13,
  curso         VARCHAR(3)   NULL     COMMENT 'CG|IG|CEJ|CFB|NULL=transversal',
  PRIMARY KEY (id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── alunos ─────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS alunos (
  id               INT          NOT NULL AUTO_INCREMENT,
  numero_processo  VARCHAR(20)  NOT NULL,
  nome_completo    VARCHAR(120) NOT NULL,
  sexo             CHAR(1)      NOT NULL COMMENT 'M|F',
  data_nascimento  DATE         NOT NULL,
  turma_id         VARCHAR(6)   NOT NULL,
  classe           VARCHAR(15)  NOT NULL,
  ativo            TINYINT(1)   NOT NULL DEFAULT 1,
  qr_token         VARCHAR(20)  NOT NULL COMMENT 'equals numero_processo — used in QR URL',
  criado_em        DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uq_numero_processo (numero_processo),
  UNIQUE KEY uq_qr_token (qr_token),
  FOREIGN KEY (turma_id) REFERENCES turmas(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── atribuicoes_disciplinas ────────────────────────────────────
CREATE TABLE IF NOT EXISTS atribuicoes_disciplinas (
  id            INT        NOT NULL AUTO_INCREMENT,
  turma_id      VARCHAR(6) NOT NULL,
  disciplina_id INT        NOT NULL,
  professor_id  INT        NOT NULL,
  PRIMARY KEY (id),
  UNIQUE KEY uq_atrib (turma_id, disciplina_id),
  FOREIGN KEY (turma_id)      REFERENCES turmas(id),
  FOREIGN KEY (disciplina_id) REFERENCES disciplinas(id),
  FOREIGN KEY (professor_id)  REFERENCES professores(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── horarios ───────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS horarios (
  id            INT        NOT NULL AUTO_INCREMENT,
  turma_id      VARCHAR(6) NOT NULL,
  disciplina_id INT        NOT NULL,
  dia_semana    TINYINT    NOT NULL COMMENT '1=Seg 2=Ter 3=Qua 4=Qui 5=Sex',
  aula          TINYINT    NOT NULL COMMENT '1..6',
  PRIMARY KEY (id),
  UNIQUE KEY uq_slot (turma_id, dia_semana, aula),
  FOREIGN KEY (turma_id)      REFERENCES turmas(id),
  FOREIGN KEY (disciplina_id) REFERENCES disciplinas(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ── presencas ──────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS presencas (
  id            INT          NOT NULL AUTO_INCREMENT,
  aluno_id      INT          NOT NULL,
  turma_id      VARCHAR(6)   NOT NULL,
  disciplina_id INT          NOT NULL,
  data          DATE         NOT NULL,
  aula          TINYINT      NULL COMMENT 'slot 1-6; NULL = unknown',
  status        VARCHAR(12)  NOT NULL DEFAULT 'Presente' COMMENT 'Presente|Falta|Justificada',
  observacao    VARCHAR(255) NULL,
  registado_em  DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
  ip_origem     VARCHAR(45)  NULL COMMENT 'IP of QR scan',
  PRIMARY KEY (id),
  UNIQUE KEY uq_presenca (aluno_id, disciplina_id, data, aula),
  FOREIGN KEY (aluno_id)      REFERENCES alunos(id),
  FOREIGN KEY (turma_id)      REFERENCES turmas(id),
  FOREIGN KEY (disciplina_id) REFERENCES disciplinas(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

SET FOREIGN_KEY_CHECKS = 1;

